$ledger="C:\Users\hp\Desktop\end-to-go\nono-gate-ci\decision\governance-ledger.ndjson";$out="C:\Users\hp\Desktop\end-to-go\nono-gate-ci\decision\LEDGER_MERKLE_ROOT_SHA256.txt";if(!(Test-Path $ledger)){throw "LEDGER_NOT_FOUND"};$lines=Get-Content $ledger|Where-Object{$_ -ne ""};$hashes=@();foreach($l in $lines){$bytes=[Text.Encoding]::UTF8.GetBytes($l);$sha=[System.Security.Cryptography.SHA256]::Create();$h=($sha.ComputeHash($bytes)|ForEach-Object ToString x2)-join "";$hashes+=$h};while($hashes.Count -gt 1){$next=@();for($i=0;$i -lt $hashes.Count;$i+=2){if($i+1 -lt $hashes.Count){$pair=$hashes[$i]+$hashes[$i+1]}else{$pair=$hashes[$i]+$hashes[$i]};$bytes=[Text.Encoding]::UTF8.GetBytes($pair);$sha=[System.Security.Cryptography.SHA256]::Create();$next+=(($sha.ComputeHash($bytes)|ForEach-Object ToString x2)-join "")};$hashes=$next};$root=$hashes[0];Set-Content -LiteralPath $out -Encoding UTF8 -Value $root;Write-Host "NONO-GATE: LEDGER MERKLE ROOT COMPUTED"
